"use client";

import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  useReactTable,
} from "@tanstack/react-table";

// ✅ Fake Data
const data = [
  { id: "1", name: "Bitcoin", symbol: "BTC", price: 65000 },
  { id: "2", name: "Ethereum", symbol: "ETH", price: 3200 },
  { id: "3", name: "Solana", symbol: "SOL", price: 150 },
];

// ✅ Columns
const columns = [
  {
    accessorKey: "name",
    header: "Coin Name",
  },
  {
    accessorKey: "symbol",
    header: "Symbol",
  },
  {
    accessorKey: "price",
    header: "Price ($)",
    cell: ({ row }: { row: any }) : any => `$${row.getValue("price")}`,
  },
];

export default function DataTable() {
  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  return (
    <div className="p-6">
      <h1 className="text-xl font-bold mb-4">Crypto Dashboard (Demo)</h1>

      <div className="overflow-hidden rounded-md border">
        <table className="w-full">
          <thead>
            {table.getHeaderGroups().map((headerGroup) => (
              <tr key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <th key={header.id} className="p-3 text-left border-b">
                    {flexRender(
                      header.column.columnDef.header,
                      header.getContext()
                    )}
                  </th>
                ))}
              </tr>
            ))}
          </thead>

          <tbody>
            {table.getRowModel().rows.map((row) => (
              <tr key={row.id} className="border-b">
                {row.getVisibleCells().map((cell) => (
                  <td key={cell.id} className="p-3">
                    {flexRender(
                      cell.column.columnDef.cell,
                      cell.getContext()
                    )}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}